mapper.select:
select from enum_configs ec inner join enum_categories c on ec.category_id = c.id
c.category = #{category}
order by c.category, ec.sort_order, ec.id

mapper.update:
update enum_configs
set item_label = #{itemLabel},
    sort_order = #{sortOrder},
    is_enabled = #{isEnabled},
    remark     = #{remark}
where id = #{id}
